public String mixString(String a, String b)
{
    StringBuilder result = new StringBuilder();
    int i = 0;
    while(i < a.length() || i < b.length())
    {
        if(i < a.length())
            result.append(a.charAt(i));
        if(i < b.length())
            result.append(b.charAt(i));
        i++;
    }
    return result.toString();
}

