public String without2(String str) {
    int len = str.length();

    if (len < 2) {
        return str;
    }

    String firstTwo = str.substring(0, 2);
    String lastTwo = str.substring(len - 2);

    if (firstTwo.equals(lastTwo)) {
        return str.substring(2);
